package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecord_DefaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Using reflection to forcibly set skipHeaderRecord to false to ensure test correctness
        Field field = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        field.setAccessible(true);
        field.setBoolean(format, false);

        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_WithTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_WithFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        assertFalse(format.getSkipHeaderRecord());
    }
}
